// ❌ Compile error pattern
class Parent {
    Parent(String msg) { // Only a parameterized constructor
        System.out.println(msg);
    }
    // → Default constructor Parent() is NOT auto-generated!
}

class Child extends Parent {
    Child() {
        // super() is implicitly inserted
        // → Parent() doesn't exist, so compile error!
    }
}

// ✅ Fix 1: Explicitly call super(argument)
class Child extends Parent {
    Child() {
        super("hello"); // Call parent's parameterized constructor
    }
}

// ✅ Fix 2: Add a no-argument constructor to the parent
class Parent {
    Parent() {}            // Add no-argument constructor
    Parent(String msg) {}  // Parameterized constructor
}

