// Abstract class
// Definition of the Shape class
abstract class Shape {
    String color;

    Shape(String color) {
        this.color = color;
    }

    // Abstract method (no implementation, enforced in child classes)
    abstract double area();

    // Regular method (common logic can be written here)
    // Definition of the display method
    void display() {
        System.out.println(color + " shape, area: " + area());
    }
}

// Implement abstract methods in child classes
// Definition of the Circle class
class Circle extends Shape {
    double radius;

    Circle(String color, double radius) {
        super(color);
        this.radius = radius;
    }
    @Override
    // Definition of the area method
    double area() {
        return Math.PI * radius * radius;
    }
}

// Definition of the Rectangle class
class Rectangle extends Shape {
    double w, h;

    Rectangle(String color, double w, double h) {
        super(color);
        this.w = w;
        this.h = h;
    }
    @Override
    double area() {
        return w * h;
    }
}

// Shape s = new Shape("red"); // Compile error! Cannot instantiate an abstract class
Shape s = new Circle("red", 5.0);
s.display(); // red shape, area: 78.539...

