// Definition of the Greeter interface
interface Greeter {
    // Abstract method (implementation required)
    String getName();

    // Default method (has a default implementation, override is optional)
    default void greet() {
        System.out.println("Hello, " + getName());
    }

    // Static method (called using the interface name)
    // Definition of the info method
    static void info() {
        System.out.println("Greeter interface v1.0");
    }
}

// Definition of the User class
class User implements Greeter {
    private String name;
    User(String name) { this.name = name; }

    @Override
    // Definition of the getName method
    public String getName() { return name; }
    // greet() can use the default implementation as-is
}

User u = new User("Alice");
u.greet();       // Hello, Alice (default implementation)
Greeter.info();  // Greeter interface v1.0 (static call)

// It's also possible to override the default method
// Definition of the VIPUser class
class VIPUser implements Greeter {
    @Override public String getName() { return "VIP"; }
    @Override public void greet() {
        System.out.println("Special greeting: Dear " + getName());
    }
}

