class Vehicle {
    void run() { System.out.println("Running"); }
}
class Car extends Vehicle {
    void drift() { System.out.println("Drifting!"); }
}

// Upcasting (child → parent): implicit, always safe
Vehicle v = new Car();  // Automatic (no cast needed)
v.run();                // OK
// v.drift();           // Compile error! Vehicle type has no drift()

// Downcasting (parent → child): explicit cast required
Car c = (Car) v;        // Cast (actual type is Car, so it's OK)
c.drift();              // OK → Drifting!

// ⚠️ Downcasting to a type different from the actual type causes a runtime error
Vehicle v2 = new Vehicle(); // Actual type is Vehicle
// Car c2 = (Car) v2;      // ClassCastException!

// Safe downcasting: check with instanceof first
if (v instanceof Car) {
    Car safeCar = (Car) v;  // Safe
    safeCar.drift();
}

