// Definition of the Shape class
abstract class Shape {
    abstract double area();

    @Override
    // Definition of the toString method
    public String toString() {
        return getClass().getSimpleName() + ": area=" + area();
    }
}

// Definition of the Circle class
class Circle extends Shape {
    double r;
    Circle(double r) { this.r = r; }
    @Override double area() { return Math.PI * r * r; }
}

// Definition of the Rect class
class Rect extends Shape {
    double w, h;
    Rect(double w, double h) { this.w = w; this.h = h; }
    @Override double area() { return w * h; }
}

// Polymorphism: different behaviors through the same Shape type
Shape[] shapes = {
    new Circle(5),
    new Rect(3, 4),
    new Circle(2)
};

// Enhanced for loop (iterates over all elements of a collection)
for (Shape s : shapes) {
    System.out.println(s.toString());
    // Circle: area=78.539...
    // Rect: area=12.0
    // Circle: area=12.566...
}

// Total area is easy to calculate
// Variable declaration and initialization
double total = 0;
for (Shape s : shapes) total += s.area();
System.out.println("Total area: " + total);

// Key methods of the Object class:
// toString() — Returns a string representation
// equals()   — Determines equality
// hashCode() — Returns a hash value

// Definition of the Student class
class Student {
    String name;
    int id;

    Student(String name, int id) {
        this.name = name;
        this.id = id;
    }
    @Override
    // Definition of the toString method
    public String toString() {
        return "Student{name='" + name + "', id=" + id + "}";
    }
    @Override
    // Definition of the equals method
    public boolean equals(Object obj) {
        // Conditional branch
        if (this == obj) return true;
        if (!(obj instanceof Student)) return false;
        Student other = (Student) obj;
        return this.id == other.id &&
               this.name.equals(other.name);
    }
    @Override
    public int hashCode() {
        return name.hashCode() * 31 + id;
    }
}
Student s1 = new Student("Taro", 1);
Student s2 = new Student("Taro", 1);
System.out.println(s1.toString()); // Student{name='Taro', id=1}
System.out.println(s1.equals(s2)); // true
System.out.println(s1 == s2);      // false (reference comparison)

